function getTodayIndex() {
  const now = new Date();
  // Use Cyprus timezone (UTC+3 in summer) вЂ” device locale does not matter
  const fmt = new Intl.DateTimeFormat('en-US', {
    timeZone: 'Asia/Nicosia',
    year: 'numeric', month: 'numeric', day: 'numeric', hour: 'numeric', hour12: false,
  });
  const p = {};
  fmt.formatToParts(now).forEach(({ type, value }) => { p[type] = parseInt(value, 10); });
  let m = p.month - 1, d = p.day, h = p.hour % 24;
  if (h < 2) { // РґРѕ 02:00 РїРѕ РљРёРїСЂСѓ вЂ” РІСЃС‘ РµС‰С‘ РїСЂРµРґС‹РґСѓС‰РёР№ РґРµРЅСЊ
    const prev = new Date(now.getTime() - 86400000);
    const p2 = {};
    fmt.formatToParts(prev).forEach(({ type, value }) => { p2[type] = parseInt(value, 10); });
    m = p2.month - 1; d = p2.day;
  }
  if (m === 5 && d >= 2 && d <= 5) return d - 2; // 2в†’0, 3в†’1, 4в†’2, 5в†’3
  if (m < 5 || (m === 5 && d < 2)) return 0;     // РґРѕ РјРµСЂРѕРїСЂРёСЏС‚РёСЏ вЂ” РґРµРЅСЊ 1
  return 3;                                        // РїРѕСЃР»Рµ вЂ” РґРµРЅСЊ 4
}
